    let tabs=[],current=0;

    function normalize(u){
      try{return new URL(u).href}
      catch{
        try{return new URL('https://'+u).href}
        catch{return null}
      }
    }

    function renderTabs(){
      const c=document.getElementById('tabBar');
      c.innerHTML='';
      tabs.forEach((t,i)=>{
        const e=document.createElement('div');
        e.className='tab'+(i===current?' active':'');

        const title=document.createElement('span');
        title.textContent=t.title;

        const close=document.createElement('span');
        close.textContent='×';
        close.onclick=(ev)=>{ev.stopPropagation();closeTab(i);};

        e.appendChild(title);
        e.appendChild(close);
        e.onclick=()=>switchTab(i);
        c.appendChild(e);
      });
    }

    function addTab(u){
      const v=normalize(u);
      if(!v) return alert('Invalid URL');
      const t=new URL(v).hostname.replace('www.','');
      tabs.push({url:v,title:t});
      current=tabs.length-1;
      load();
    }

    function switchTab(i){
      if(!tabs[i]) return;
      current=i;
      load();
    }

    function load(){
      if(!tabs.length) return;
      document.getElementById('mainFrame').src=tabs[current].url;
      renderTabs();
    }

    function closeTab(i){
      if(tabs.length<=1) return;
      tabs.splice(i,1);
      if(current>=tabs.length) current=tabs.length-1;
      load();
    }

    function goUrl(){
      const v=document.getElementById('urlInput').value.trim();
      if(v) addTab(v);
    }

    function customize(){
      const n=prompt('New name?',document.title);
      if(n)document.title=n;
    }

    function panic(){
      document.body.style.display='none';
      setTimeout(()=>document.body.style.display='flex',1200);
    }

    let esc=0,timer;
    document.addEventListener('keydown',e=>{
      if(e.key==='Escape'){
        esc++;
        clearTimeout(timer);
        timer=setTimeout(()=>esc=0,500);
        if(esc>=2){
          document.body.style.display='none';
          setTimeout(()=>document.body.style.display='flex',1000);
          esc=0;
        }
      }
    });

    // jsDelivr hook (optional repo logic)
    const s=document.createElement('script');
    s.src='https://cdn.jsdelivr.net/gh/jared20010813-stack/NexusForge@main/app.js';
    document.body.appendChild(s);

    addTab('https://google.com');




